  title: "En el supermercado",
  titleNative: "In de supermarkt",
  focus: "Hoy aprenderás vocabulario para comprar comida y productos básicos. Esto te ayudará si te alojas en un apartamento o quieres ahorrar durante el viaje.",
  vocab: [{ nl: "supermarkt", es: "supermercado", ipa: "/sü-per-markt/" }, { nl: "mandje", es: "cesta", ipa: "/mán-chie/" }, { nl: "tas", es: "bolsa", ipa: "/tas/" }, { nl: "brood", es: "pan", ipa: "/brot/" }, { nl: "melk", es: "leche", ipa: "/melk/" }, { nl: "eieren", es: "huevos", ipa: "/éi-e-ren/" }, { nl: "appels", es: "manzanas", ipa: "/á-pels/" }, { nl: "kaas", es: "queso", ipa: "/kaas/" }, { nl: "kassa", es: "caja", ipa: "/ká-sa/" }, { nl: "bon", es: "recibo", ipa: "/bon/" }],
  phrases: [{ nl: "Waar zijn de eieren?", es: "¿Dónde están los huevos?", ipa: "/vaar záin de éi-e-ren/" }, { nl: "Heeft u een tas nodig?", es: "¿Necesita una bolsa?", ipa: "/jeift ü ein tas nó-daj/" }, { nl: "Ik heb geen tas nodig.", es: "No necesito bolsa.", ipa: "/ik jeb jein tas nó-daj/" }, { nl: "Kan ik pinnen?", es: "¿Puedo pagar con tarjeta?", ipa: "/kan ik pí-nen/" }, { nl: "Mag ik de bon?", es: "¿Me da el recibo?", ipa: "/maj ik de bon/" }, { nl: "Dat is alles.", es: "Eso es todo.", ipa: "/dat is á-les/" }],
  grammar: "“Pinnen” es una palabra muy común en los Países Bajos y significa pagar con tarjeta o con PIN. En supermercados, muchas cajas preguntan si quieres recibo o bolsa. “Dat is alles” es una frase corta y útil para cerrar una compra.",
  practice: ["Pregunta dónde están los huevos.", "Di que no necesitas bolsa.", "Pregunta si puedes pagar con tarjeta.", "Pide el recibo.", "Enumera tres productos básicos en neerlandés."]
