  phrases: [{ nl: "Ik zoek een blauwe jas.", es: "Busco una chaqueta azul.", ipa: "/ik zuk ein blau-e yas/" }, { nl: "Heeft u dit in het zwart?", es: "¿Tiene esto en negro?", ipa: "/jeift ü dit in jet zvart/" }, { nl: "Dat is mooi.", es: "Eso es bonito.", ipa: "/dat is mói/" }, { nl: "Ik wil iets kleiner.", es: "Quiero algo más pequeño.", ipa: "/ik vil its klèi-ner/" }, { nl: "Is er een grotere maat?", es: "¿Hay una talla más grande?", ipa: "/is er ein jró-te-re maat/" }, { nl: "De rode is leuk.", es: "El rojo es bonito.", ipa: "/de ró-de is leuk/" }],
  grammar: "Los adjetivos neerlandeses a menudo añaden una “-e” antes del sustantivo: “blauwe jas”, “rode tas”. No siempre ocurre, pero como regla práctica para principiantes, escucharás mucho esa “-e”. Para comparar, se suele añadir “-er”: “kleiner”, “groter”, “goedkoper”.",
  practice: ["Di que buscas una chaqueta azul.", "Pregunta si algo está en negro.", "Describe un objeto bonito.", "Pide una talla más grande.", "Practica cinco colores en voz alta."]
