  vocab: [{ nl: "weer", es: "clima/tiempo", ipa: "/vir/" }, { nl: "regen", es: "lluvia", ipa: "/rei-jen/" }, { nl: "wind", es: "viento", ipa: "/vint/" }, { nl: "zon", es: "sol", ipa: "/zon/" }, { nl: "koud", es: "frío", ipa: "/kaut/" }, { nl: "warm", es: "cálido/calor", ipa: "/varm/" }, { nl: "bewolkt", es: "nublado", ipa: "/be-volkt/" }, { nl: "paraplu", es: "paraguas", ipa: "/pa-ra-plü/" }, { nl: "jas", es: "chaqueta", ipa: "/yas/" }, { nl: "laarzen", es: "botas", ipa: "/lár-zen/" }],
  phrases: [{ nl: "Hoe is het weer vandaag?", es: "¿Cómo está el clima hoy?", ipa: "/ju is jet vir van-daaj/" }, { nl: "Het regent.", es: "Llueve.", ipa: "/jet rei-jent/" }, { nl: "Het is koud.", es: "Hace frío.", ipa: "/jet is kaut/" }, { nl: "Er is veel wind.", es: "Hay mucho viento.", ipa: "/er is veil vint/" }, { nl: "Ik heb een paraplu nodig.", es: "Necesito un paraguas.", ipa: "/ik jeb ein pa-ra-plü nó-daj/" }, { nl: "Morgen wordt het warmer.", es: "Mañana hará más calor.", ipa: "/mór-jen vordt jet var-mer/" }],
