var CONVERSATIONS_ES_NL = [
{ title: "Pedir en una cafetería en Ámsterdam", scene: "Estás en una cafetería pequeña cerca de un canal en Ámsterdam. Quieres pedir café y algo sencillo para comer, y decides practicar neerlandés.", lines: [{ who: "them", nl: "Goedemorgen, wat wilt u drinken?", es: "Buenos días, ¿qué quiere beber?" }, { who: "you", nl: "Goedemorgen, een koffie alstublieft.", es: "Buenos días, un café por favor." }, { who: "them", nl: "Met melk of zonder melk?", es: "¿Con leche o sin leche?" }, { who: "you", nl: "Met melk, graag.", es: "Con leche, por favor." }, { who: "them", nl: "Wilt u ook iets eten?", es: "¿Quiere también algo de comer?" }, { who: "you", nl: "Ja, een broodje kaas alstublieft.", es: "Sí, un bocadillo de queso por favor." }, { who: "them", nl: "Voor hier of om mee te nemen?", es: "¿Para tomar aquí o para llevar?" }, { who: "you", nl: "Voor hier, graag.", es: "Para tomar aquí, por favor." }, { who: "them", nl: "Dat is zeven euro vijftig.", es: "Son siete euros con cincuenta." }, { who: "you", nl: "Ik betaal met kaart.", es: "Pago con tarjeta." }, { who: "them", nl: "Prima, alstublieft.", es: "Perfecto, aquí tiene." }, { who: "you", nl: "Dank u wel.", es: "Muchas gracias." }] },
{ title: "Registrarse en un hotel en Utrecht", scene: "Llegas a un hotel en Utrecht después de un viaje en tren. Tienes una reserva a tu nombre y quieres confirmar el desayuno y la hora de salida.", lines: [{ who: "them", nl: "Goedenavond, welkom in ons hotel.", es: "Buenas noches, bienvenido a nuestro hotel." }, { who: "you", nl: "Goedenavond, ik heb een reservering.", es: "Buenas noches, tengo una reserva." }, { who: "them", nl: "Op welke naam staat de reservering?", es: "¿A qué nombre está la reserva?" }, { who: "you", nl: "De reservering staat op mijn naam, García.", es: "La reserva está a mi nombre, García." }, { who: "them", nl: "Mag ik uw paspoort zien?", es: "¿Puedo ver su pasaporte?" }, { who: "you", nl: "Ja, hier is mijn paspoort.", es: "Sí, aquí está mi pasaporte." }, { who: "them", nl: "U heeft kamer drie op de tweede verdieping.", es: "Tiene la habitación tres en la segunda planta." }, { who: "you", nl: "Dank u, is ontbijt inbegrepen?", es: "Gracias, ¿está incluido el desayuno?" }, { who: "them", nl: "Ja, ontbijt is van zeven tot tien uur.", es: "Sí, el desayuno es de siete a diez." }, { who: "you", nl: "Hoe laat is uitchecken?", es: "¿A qué hora es el check-out?" }, { who: "them", nl: "Uitchecken is om elf uur.", es: "El check-out es a las once." }, { who: "you", nl: "Prima, dank u wel.", es: "Perfecto, muchas gracias." }] },
{ title: "Preguntar direcciones hacia la estación", scene: "Estás en el centro de Róterdam y necesitas llegar a la estación central. Te acercas a una persona en la calle y preguntas de forma educada.", lines: [{ who: "you", nl: "Pardon, mag ik iets vragen?", es: "Disculpe, ¿puedo preguntar algo?" }, { who: "them", nl: "Ja natuurlijk.", es: "Sí, claro." }, { who: "you", nl: "Waar is het station?", es: "¿Dónde está la estación?" }, { who: "them", nl: "Ga rechtdoor en sla dan linksaf.", es: "Siga recto y luego gire a la izquierda." }, { who: "you", nl: "Is het ver?", es: "¿Está lejos?" }, { who: "them", nl: "Nee, het is dichtbij.", es: "No, está cerca." }, { who: "you", nl: "Hoe lang lopen?", es: "¿Cuánto tiempo caminando?" }, { who: "them", nl: "Ongeveer tien minuten.", es: "Aproximadamente diez minutos." }, { who: "you", nl: "Moet ik over de brug?", es: "¿Tengo que cruzar el puente?" }, { who: "them", nl: "Ja, over de brug en dan rechts.", es: "Sí, cruce el puente y luego a la derecha." }, { who: "you", nl: "Dank u wel voor uw hulp.", es: "Muchas gracias por su ayuda." }, { who: "them", nl: "Geen probleem, fijne dag.", es: "No hay problema, buen día." }] },
{ title: "Comer en un restaurante en Leiden", scene: "Estás en un restaurante acogedor en Leiden. Quieres una mesa, pedir recomendación y pagar la cuenta al final.", lines: [{ who: "them", nl: "Goedenavond, heeft u gereserveerd?", es: "Buenas noches, ¿tiene reserva?" }, { who: "you", nl: "Nee, heeft u een tafel voor twee?", es: "No, ¿tiene una mesa para dos?" }, { who: "them", nl: "Ja, natuurlijk, volg mij maar.", es: "Sí, claro, sígame." }, { who: "you", nl: "Mag ik het menu zien?", es: "¿Puedo ver el menú?" }, { who: "them", nl: "Natuurlijk, hier is het menu.", es: "Por supuesto, aquí está el menú." }, { who: "you", nl: "Wat raadt u aan?", es: "¿Qué recomienda usted?" }, { who: "them", nl: "De verse vis is vandaag heel lekker.", es: "El pescado fresco está muy rico hoy." }, { who: "you", nl: "Prima, ik neem de vis.", es: "Perfecto, me llevo el pescado." }, { who: "them", nl: "Wilt u ook iets drinken?", es: "¿Quiere también algo de beber?" }, { who: "you", nl: "Een glas water en een witte wijn, graag.", es: "Un vaso de agua y un vino blanco, por favor." }, { who: "them", nl: "Komt eraan.", es: "Enseguida." }, { who: "you", nl: "Dank u wel.", es: "Muchas gracias." }] },
{ title: "Comprar billetes de tren", scene: "Estás en la estación central de Ámsterdam y quieres viajar a Utrecht. Necesitas saber el andén y si hay retraso.", lines: [{ who: "them", nl: "Goedemiddag, kan ik u helpen?", es: "Buenas tardes, ¿puedo ayudarle?" }, { who: "you", nl: "Ja, ik wil een kaartje naar Utrecht.", es: "Sí, quiero un billete a Utrecht." }, { who: "them", nl: "Enkele reis of retour?", es: "¿Solo ida o ida y vuelta?" }, { who: "you", nl: "Retour, alstublieft.", es: "Ida y vuelta, por favor." }, { who: "them", nl: "Dat is achttien euro.", es: "Son dieciocho euros." }, { who: "you", nl: "Ik betaal met kaart.", es: "Pago con tarjeta." }, { who: "them", nl: "Prima, hier is uw kaartje.", es: "Perfecto, aquí tiene su billete." }, { who: "you", nl: "Op welk perron vertrekt de trein?", es: "¿De qué andén sale el tren?" }, { who: "them", nl: "Perron vijf.", es: "Andén cinco." }, { who: "you", nl: "Is er vertraging?", es: "¿Hay retraso?" }, { who: "them", nl: "Nee, de trein vertrekt op tijd.", es: "No, el tren sale a tiempo." }, { who: "you", nl: "Dank u wel.", es: "Muchas gracias." }] },
{ title: "Comprar ropa en una tienda", scene: "Estás en una tienda de ropa en Maastricht. Buscas una chaqueta azul, quieres probártela y preguntar por otra talla.", lines: [{ who: "them", nl: "Hallo, kan ik u helpen?", es: "Hola, ¿puedo ayudarle?" }, { who: "you", nl: "Ja, ik zoek een blauwe jas.", es: "Sí, busco una chaqueta azul." }, { who: "them", nl: "Welke maat heeft u?", es: "¿Qué talla tiene?" }, { who: "you", nl: "Heeft u deze maat?", es: "¿Tiene esta talla?" }, { who: "them", nl: "Ja, hier is een blauwe jas.", es: "Sí, aquí tiene una chaqueta azul." }, { who: "you", nl: "Mag ik dit passen?", es: "¿Puedo probarme esto?" }, { who: "them", nl: "Natuurlijk, de paskamer is daar.", es: "Claro, el probador está allí." }, { who: "you", nl: "Dank u, het is een beetje klein.", es: "Gracias, es un poco pequeño." }, { who: "them", nl: "Wilt u een grotere maat?", es: "¿Quiere una talla más grande?" }, { who: "you", nl: "Ja, graag.", es: "Sí, por favor." }, { who: "them", nl: "Hier is de grotere maat.", es: "Aquí tiene la talla más grande." }, { who: "you", nl: "Perfect, ik neem deze.", es: "Perfecto, me llevo esta." }] },
{ title: "Pedir ayuda en una farmacia", scene: "Estás resfriado durante tu viaje en La Haya. Entras en una farmacia para pedir algo para la tos y saber cómo tomarlo.", lines: [{ who: "them", nl: "Goedemiddag, waarmee kan ik u helpen?", es: "Buenas tardes, ¿en qué puedo ayudarle?" }, { who: "you", nl: "Ik ben verkouden en ik heb hoest.", es: "Estoy resfriado y tengo tos." }, { who: "them", nl: "Heeft u ook koorts?", es: "¿Tiene también fiebre?" }, { who: "you", nl: "Nee, geen koorts.", es: "No, no tengo fiebre." }, { who: "them", nl: "Dan raad ik deze siroop aan.", es: "Entonces le recomiendo este jarabe." }, { who: "you", nl: "Hoe vaak moet ik dit nemen?", es: "¿Con qué frecuencia debo tomar esto?" }, { who: "them", nl: "Drie keer per dag na het eten.", es: "Tres veces al día después de comer." }, { who: "you", nl: "Heeft u ook iets tegen hoofdpijn?", es: "¿Tiene también algo para el dolor de cabeza?" }, { who: "them", nl: "Ja, paracetamol staat hier.", es: "Sí, el paracetamol está aquí." }, { who: "you", nl: "Dank u, ik neem beide.", es: "Gracias, me llevo ambos." }, { who: "them", nl: "Beterschap.", es: "Que se mejore." }, { who: "you", nl: "Dank u wel.", es: "Muchas gracias." }] },
{ title: "Charla sencilla con una persona local", scene: "Estás sentado en una terraza en Haarlem y una persona local empieza una conversación amable. Practicas frases sobre viajes, ciudades y aprender neerlandés.", lines: [{ who: "you", nl: "Hallo, is deze stoel vrij?", es: "Hola, ¿está libre esta silla?" }, { who: "them", nl: "Ja hoor, ga zitten.", es: "Sí, claro, siéntese." }, { who: "you", nl: "Dank je, het is hier gezellig.", es: "Gracias, aquí hay buen ambiente." }, { who: "them", nl: "Ja, dit café is heel leuk.", es: "Sí, este café es muy agradable." }, { who: "you", nl: "Woon je hier in Haarlem?", es: "¿Vives aquí en Haarlem?" }, { who: "them", nl: "Ja, ik woon hier al vijf jaar.", es: "Sí, vivo aquí desde hace cinco años." }, { who: "you", nl: "Ik ben hier op vakantie.", es: "Estoy aquí de vacaciones." }, { who: "them", nl: "Leuk, waar kom je vandaan?", es: "Qué bien, ¿de dónde eres?" }, { who: "you", nl: "Ik kom uit Spanje en ik leer Nederlands.", es: "Vengo de España y estoy aprendiendo neerlandés." }, { who: "them", nl: "Je spreekt al goed Nederlands.", es: "Ya hablas bien neerlandés." }, { who: "you", nl: "Dank je, maar ik spreek alleen een beetje.", es: "Gracias, pero solo hablo un poco." }, { who: "them", nl: "Dat is al heel goed.", es: "Eso ya está muy bien." }] }
];
